/**
 * Script embed entry.
 *
 * Builds to dist/panorama360.min.js and exposes:
 *   window.Panorama360.init({ projectId, container?, backendUrl? | backend_url? })
 *   window.Panorama360.loadPanorama(id)
 *   window.Panorama360.enterVR()
 *   window.Panorama360.exitVR()
 *   window.Panorama360.toggleFloorplan()
 *   window.Panorama360.destroy()
 */

import './styles/viewer.css';
import { Viewer } from './core/ViewerPsv.js';
import { ensureViewerStyles } from './core/ensureViewerStyles.js';

let _active = null;

export async function init(options) {
  ensureViewerStyles();
  if (_active) await _active.destroy();
  const opts = { ...(options || {}) };

  // If container is omitted, create a default mount point.
  if (!opts.container && typeof document !== 'undefined') {
    const id = 'panorama360-root';
    let el = document.getElementById(id);
    if (!el) {
      el = document.createElement('div');
      el.id = id;
      el.style.width = '100%';
      // Reasonable default height so it "just works".
      el.style.height = '600px';
      document.body.appendChild(el);
    }
    opts.container = el;
  }

  const backendUrlRaw =
    opts.backendUrl ||
    opts.backend_url ||
    opts.apiBaseUrl || // backwards compat
    import.meta.env.VITE_BACKEND_URL ||
    import.meta.env.VITE_API_BASE_URL ||
    'http://46.225.89.136/api';

  const backendUrl = (backendUrlRaw || '').toString().trim();

  _active = new Viewer({ ...opts, backendUrl });
  await _active.init();
  return _active;
}

export async function loadPanorama(id) {
  if (!_active) throw new Error('Panorama360: call init() first');
  return await _active.loadPanorama(id, { reason: 'api' });
}

export function getViewYawPitch() {
  if (!_active) throw new Error('Panorama360: call init() first');
  return _active.getViewYawPitch();
}

export function toggleFloorplan() {
  if (!_active) throw new Error('Panorama360: call init() first');
  return _active.toggleFloorplan();
}

export async function enterVR() {
  if (!_active) throw new Error('Panorama360: call init() first');
  return await _active.enterVR();
}

export async function exitVR() {
  if (!_active) throw new Error('Panorama360: call init() first');
  return await _active.exitVR();
}

export async function destroy() {
  if (!_active) return;
  const v = _active;
  _active = null;
  await v.destroy();
}

export const Panorama360 = {
  init,
  loadPanorama,
  getViewYawPitch,
  enterVR,
  exitVR,
  toggleFloorplan,
  destroy
};

// Ensure a stable global in both IIFE and ESM contexts.
if (typeof window !== 'undefined') window.Panorama360 = Panorama360;


