/**
 * Ensure viewer CSS is present for production library builds.
 *
 * Vite "lib" builds usually extract CSS into a separate `style.css` file.
 * In an iframe (or a host page), that stylesheet might not be linked, which
 * causes UI (like the floorplan) to appear unstyled or missing.
 *
 * This helper auto-injects a <link rel="stylesheet"> that points to `style.css`
 * next to the current script file (panorama360.min.js / iframe.min.js).
 */
export function ensureViewerStyles() {
  if (typeof document === 'undefined') return;

  // Already present?
  const existing = document.querySelector('link[data-p360-style], link[href*="style.css"]');
  if (existing) return;

  const script =
    document.currentScript ||
    Array.from(document.getElementsByTagName('script')).find((s) => /panorama360\.min\.js|iframe\.min\.js/i.test(s.src)) ||
    null;
  const src = script?.src || '';
  if (!src) return;

  try {
    const u = new URL(src, window.location.href);
    // Replace filename with style.css, keep any query string (cache-busting).
    u.pathname = u.pathname.replace(/(?:panorama360\.min\.js|iframe\.min\.js)$/i, 'style.css');

    const link = document.createElement('link');
    link.rel = 'stylesheet';
    link.href = u.toString();
    link.setAttribute('data-p360-style', 'true');
    document.head.appendChild(link);
  } catch {
    // Ignore; worst case host must include style.css manually.
  }
}



